import os
from PIL import Image
import subprocess

def process_image(event, context):
    # Extract filename and conversion options from event metadata
    file_name = event['name']
    bucket_name = event['bucket']
    
    # Define the input and output paths
    input_path = f'/tmp/{file_name}'
    output_path = f'/tmp/converted_{file_name}'
    
    # Download the image from Cloud Storage to local temp directory
    subprocess.call(['gsutil', 'cp', f'gs://{bucket_name}/{file_name}', input_path])
    
    # Define conversion options (example: resize to 800x600)
    convert_options = ['convert', input_path, '-resize', '800x600', output_path]
    
    # Run the ImageMagick convert command
    subprocess.call(convert_options)
    
    # Upload the converted image back to Cloud Storage
    subprocess.call(['gsutil', 'cp', output_path, f'gs://{bucket_name}/converted_{file_name}'])
    
    return {
        'statusCode': 200,
        'body': f'Image {file_name} processed and saved as converted_{file_name}'
    }